const passed = new Set<string>();
const perkMap = new Map(data.map(data => [data._id, data]));

const __dirname = url.fileURLToPath(new URL(".", import.meta.url));
const packsDataPath = path.resolve(__dirname, "../../packs/core-perks");

for(const file of fs.readdirSync(packsDataPath)) {
  if(file.startsWith("_")) continue;
  const filePath = path.resolve(packsDataPath, file);
  const data = JSON.parse(fs.readFileSync(filePath, "utf-8"));

  if(!data.system) throw new Error(`Missing system data in ${filePath}`);
  const perkData = perkMap.get(data._id);
  if(!perkData) throw new Error(`Perk not found for ${filePath}`);

  data.system = perkData.system;
  data.effects = perkData.effects || [];

  fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
  passed.add(data._id);
}

for(const [id, perk] of perkMap) {
  if(passed.has(id)) continue;
  const filePath = path.resolve(packsDataPath, `${perk.system?.slug ?? sluggify(perk.name)}.json`);
  if(fs.existsSync(filePath)) {
    const data = JSON.parse(fs.readFileSync(filePath, "utf-8"));
    data.system = perk.system;
    data.effects = perk.effects || [];
    fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
    continue;
  }

  const newData = {
    name: perk.name,
    _id: perk._id,
    type: "perk",
    img: perk.img || "systems/ptr2e/img/icons/feat_icon.webp",
    effects: perk.effects || [],
    system: perk.system,
  }
  fs.writeFileSync(filePath, JSON.stringify(newData, null, 2));
}